-- Add VM lifecycle email templates (created, deleted, reinstall completed)
INSERT INTO
	`featherpanel_mail_templates` (
		`name`,
		`subject`,
		`body`,
		`deleted`,
		`locked`
	)
VALUES
	(
		'vm_created',
		'Your VM Has Been Created!',
		'<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>VM Created</title></head><body style="background-color:#f4f4f4;color:#333;font-family:-apple-system,BlinkMacSystemFont,`Segoe UI`,Roboto,Oxygen,Ubuntu,Cantarell,sans-serif;line-height:1.6;margin:0;padding:20px"><div style="background-color:#fff;border-radius:8px;box-shadow:0 4px 6px rgba(0,0,0,.1);margin:0 auto;max-width:600px;overflow:hidden"><div style="background:linear-gradient(135deg,#667eea 0,#764ba2 100%);color:#fff;padding:40px 30px;text-align:center"><h1 style="font-size:28px;font-weight:600;margin:0 0 10px 0">VM Created Successfully</h1><p style="font-size:16px;opacity:.9;margin:0">Your virtual machine <b>{vm_hostname}</b> is ready to use!</p></div><div style="padding:40px 30px"><div style="margin-bottom:30px;text-align:center"><h2 style="color:#2d3748;font-size:24px;margin:0 0 15px 0">Hello, {first_name} {last_name}</h2><p style="color:#4a5568;font-size:16px;line-height:1.6;margin:0">Great news! Your virtual machine has been created successfully and is now running.</p></div><div style="background-color:#f0fff4;border:2px solid #9ae6b4;border-radius:8px;margin:30px 0;padding:30px;text-align:center"><h3 style="color:#2d3748;font-size:20px;margin:0 0 15px 0">VM Details</h3><p style="color:#4a5568;margin:0 0 25px 0"><b>VM Hostname:</b> {vm_hostname}<br><b>IP Address:</b> {vm_ip}<br><b>Password:</b> <code style="background:#e2e8f0;padding:4px 8px;border-radius:4px;font-family:monospace">{vm_password}</code><br><b>Status:</b> <span style="color:#38a169;font-weight:600">Running</span></p><p style="color:#4a5568;margin:0 0 25px 0">You can now access your VM using the credentials above. Make sure to change your password after first login.</p><a href="{dashboard_url}" style="background:linear-gradient(135deg,#667eea 0,#764ba2 100%);border-radius:6px;color:#fff;display:inline-block;font-size:16px;font-weight:600;padding:12px 30px;text-decoration:none;transition:transform .2s">Access Dashboard</a></div><div style="background-color:#fffbeb;border:1px solid #fed7aa;border-radius:6px;margin:30px 0;padding:20px"><h4 style="color:#d69e2e;font-size:16px;margin:0 0 10px 0">Security Reminder</h4><p style="color:#4a5568;font-size:14px;margin:0">Please change your default password immediately after logging in for the first time to ensure your VM remains secure.</p></div></div><div style="background-color:#f7fafc;border-top:1px solid #e2e8f0;padding:30px;text-align:center"><p style="color:#718096;font-size:14px;margin:0 0 10px 0">This email was sent to <b>{email}</b></p><p style="color:#718096;font-size:14px;margin:0 0 10px 0">© 2024-2025 {app_name}. All rights reserved.</p><p style="color:#718096;font-size:14px;margin:0"><a href="{support_url}" style="color:#667eea;text-decoration:none">Support</a></p></div></div></body></html>',
		'false',
		'false'
	),
	(
		'vm_deleted',
		'Your VM Has Been Deleted',
		'<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>VM Deleted</title></head><body style="background-color:#f4f4f4;color:#333;font-family:-apple-system,BlinkMacSystemFont,`Segoe UI`,Roboto,Oxygen,Ubuntu,Cantarell,sans-serif;line-height:1.6;margin:0;padding:20px"><div style="background-color:#fff;border-radius:8px;box-shadow:0 4px 6px rgba(0,0,0,.1);margin:0 auto;max-width:600px;overflow:hidden"><div style="background:linear-gradient(135deg,#e53e3e 0,#fc8181 100%);color:#fff;padding:40px 30px;text-align:center"><h1 style="font-size:28px;font-weight:600;margin:0 0 10px 0">VM Deleted</h1><p style="font-size:16px;opacity:.9;margin:0">Your virtual machine <b>{vm_hostname}</b> has been permanently deleted.</p></div><div style="padding:40px 30px"><div style="margin-bottom:30px;text-align:center"><h2 style="color:#2d3748;font-size:24px;margin:0 0 15px 0">Hello, {first_name} {last_name}</h2><p style="color:#4a5568;font-size:16px;line-height:1.6;margin:0">Your virtual machine has been permanently deleted from our system.</p></div><div style="background-color:#fed7d7;border:2px solid #feb2b2;border-radius:8px;margin:30px 0;padding:30px;text-align:center"><h3 style="color:#2d3748;font-size:20px;margin:0 0 15px 0">Deletion Details</h3><p style="color:#4a5568;margin:0 0 25px 0"><b>VM Hostname:</b> {vm_hostname}<br><b>Status:</b> <span style="color:#e53e3e;font-weight:600">Deleted</span></p><p style="color:#4a5568;margin:0 0 25px 0">All data associated with this VM has been permanently removed and cannot be recovered.</p></div></div><div style="background-color:#f7fafc;border-top:1px solid #e2e8f0;padding:30px;text-align:center"><p style="color:#718096;font-size:14px;margin:0 0 10px 0">This email was sent to <b>{email}</b></p><p style="color:#718096;font-size:14px;margin:0 0 10px 0">© 2024-2025 {app_name}. All rights reserved.</p><p style="color:#718096;font-size:14px;margin:0"><a href="{support_url}" style="color:#667eea;text-decoration:none">Support</a></p></div></div></body></html>',
		'false',
		'false'
	),
	(
		'vm_reinstall_completed',
		'Your VM Reinstall Has Completed',
		'<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>VM Reinstall Completed</title></head><body style="background-color:#f4f4f4;color:#333;font-family:-apple-system,BlinkMacSystemFont,`Segoe UI`,Roboto,Oxygen,Ubuntu,Cantarell,sans-serif;line-height:1.6;margin:0;padding:20px"><div style="background-color:#fff;border-radius:8px;box-shadow:0 4px 6px rgba(0,0,0,.1);margin:0 auto;max-width:600px;overflow:hidden"><div style="background:linear-gradient(135deg,#3182ce 0,#63b3ed 100%);color:#fff;padding:40px 30px;text-align:center"><h1 style="font-size:28px;font-weight:600;margin:0 0 10px 0">VM Reinstall Completed</h1><p style="font-size:16px;opacity:.9;margin:0">Your virtual machine <b>{vm_hostname}</b> has been reinstalled successfully!</p></div><div style="padding:40px 30px"><div style="margin-bottom:30px;text-align:center"><h2 style="color:#2d3748;font-size:24px;margin:0 0 15px 0">Hello, {first_name} {last_name}</h2><p style="color:#4a5568;font-size:16px;line-height:1.6;margin:0">Your VM reinstall has completed successfully. Your virtual machine is now running with a fresh installation.</p></div><div style="background-color:#ebf8ff;border:2px solid #90cdf4;border-radius:8px;margin:30px 0;padding:30px;text-align:center"><h3 style="color:#2d3748;font-size:20px;margin:0 0 15px 0">VM Details</h3><p style="color:#4a5568;margin:0 0 25px 0"><b>VM Hostname:</b> {vm_hostname}<br><b>IP Address:</b> {vm_ip}<br><b>New Password:</b> <code style="background:#e2e8f0;padding:4px 8px;border-radius:4px;font-family:monospace">{vm_password}</code><br><b>Status:</b> <span style="color:#3182ce;font-weight:600">Running</span></p><p style="color:#4a5568;margin:0 0 25px 0">Your VM has been reinstalled with a clean operating system. All previous data has been removed. Use the new credentials above to access your VM.</p><a href="{dashboard_url}" style="background:linear-gradient(135deg,#3182ce 0,#63b3ed 100%);border-radius:6px;color:#fff;display:inline-block;font-size:16px;font-weight:600;padding:12px 30px;text-decoration:none;transition:transform .2s">Access Dashboard</a></div><div style="background-color:#fffbeb;border:1px solid #fed7aa;border-radius:6px;margin:30px 0;padding:20px"><h4 style="color:#d69e2e;font-size:16px;margin:0 0 10px 0">Important Notice</h4><p style="color:#4a5568;font-size:14px;margin:0">All previous data on this VM has been permanently deleted. Make sure to change your password after logging in and set up your applications again.</p></div></div><div style="background-color:#f7fafc;border-top:1px solid #e2e8f0;padding:30px;text-align:center"><p style="color:#718096;font-size:14px;margin:0 0 10px 0">This email was sent to <b>{email}</b></p><p style="color:#718096;font-size:14px;margin:0 0 10px 0">© 2024-2025 {app_name}. All rights reserved.</p><p style="color:#718096;font-size:14px;margin:0"><a href="{support_url}" style="color:#667eea;text-decoration:none">Support</a></p></div></div></body></html>',
		'false',
		'false'
	);
